import{_ as a,o as t,c as o,a6 as i}from"./chunks/framework.CgU7tkAh.js";const p=JSON.parse('{"title":"Profile","description":"","frontmatter":{"outline":{"level":[2,3]}},"headers":[],"relativePath":"admin/user/profile.md","filePath":"admin/user/profile.md"}'),r={name:"admin/user/profile.md"};function n(s,e,c,l,d,u){return t(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="profile" tabindex="-1">Profile <a class="header-anchor" href="#profile" aria-label="Permalink to “Profile”">​</a></h1><p>Profile allows user to see the profile information and perform profile-related changes.</p><h2 id="information" tabindex="-1">Information <a class="header-anchor" href="#information" aria-label="Permalink to “Information”">​</a></h2><ul><li><code>email</code> - user&#39;s email address</li><li><code>name</code> - user&#39;s name</li><li><code>phone</code> - user&#39;s phone number</li></ul><h3 id="change-password" tabindex="-1">Change password <a class="header-anchor" href="#change-password" aria-label="Permalink to “Change password”">​</a></h3><p>User can change their password by entering the current password and the new password twice.</p><h2 id="access" tabindex="-1">Access <a class="header-anchor" href="#access" aria-label="Permalink to “Access”">​</a></h2><ul><li><p><code>assigned roles</code> - list of roles that user was assigned to</p></li><li><p><code>assigned permissions</code> - list of permissions that user was granted</p></li></ul><h2 id="settings" tabindex="-1">Settings <a class="header-anchor" href="#settings" aria-label="Permalink to “Settings”">​</a></h2><ul><li><code>language</code> - user&#39;s preferred language</li></ul><h2 id="multi-factor-authentication" tabindex="-1">Multi-factor authentication <a class="header-anchor" href="#multi-factor-authentication" aria-label="Permalink to “Multi-factor authentication”">​</a></h2><p>Multi-factor authentication can be set up by adding at least one authentication method and then enabling the multi-factor authentication toggle.</p><p>To set up your multi-factor authentication, log into the admin tool, then click on <code>Profile</code> at the top right of the screen. Scroll down to the <code>Multi-factor authentication</code> section then click on <code>Add Device</code>. From there you can add your preferred methods.</p><p>Once you have set up your device, you will be able to select the <code>Enable multi-factor authentication</code> setting under your Profile page.</p><div class="warning custom-block"><p class="custom-block-title custom-block-title-default">WARNING</p><p>It is encouraged to set up more than one multi-factor authentication method to avoid being locked out of your account in case your primary method is unavailable.</p></div><h3 id="one-time-password-otp" tabindex="-1">One-time password (OTP) <a class="header-anchor" href="#one-time-password-otp" aria-label="Permalink to “One-time password (OTP)”">​</a></h3><p>One-time password (OTP) authentication method can be set up by installing an authenticator app (e.g. <code>Google Authenticator</code>, <code>MS Authenticator</code>, <code>Ente Auth</code> etc) and scanning the QR code or entering the secret key manually.</p><h3 id="passkey-fido2-webauthn" tabindex="-1">Passkey (FIDO2 / WebAuthn) <a class="header-anchor" href="#passkey-fido2-webauthn" aria-label="Permalink to “Passkey (FIDO2 / WebAuthn)”">​</a></h3><p>Several <code>FIDO2</code> / <code>WebAuthn</code> authentication methods are available based on user&#39;s browser / platform support:</p><ul><li><p>platform <code>passkey</code> authentication flows (e.g. fingerprint, face recognition, PIN) - available on supported mobile devices and desktop platforms</p></li><li><p>hardware security key (e.g. YubiKey)</p></li></ul><h3 id="backup-codes" tabindex="-1">Backup codes <a class="header-anchor" href="#backup-codes" aria-label="Permalink to “Backup codes”">​</a></h3><p>Backup codes can be used as a fallback authentication method when other methods are unavailable. Each code can be used only once. It is recommended to generate backup codes and store them in a safe place when setting up multi-factor authentication.</p><h3 id="duo-security" tabindex="-1">Duo Security <a class="header-anchor" href="#duo-security" aria-label="Permalink to “Duo Security”">​</a></h3><p>Optionally, <a href="https://duo.com" target="_blank" rel="noreferrer">Duo Security</a> can be used as a multi-factor authentication provider. Intake24 supports <a href="https://duo.com/docs/duoweb" target="_blank" rel="noreferrer">Universal Prompt</a> authentication method.</p><p>Check that relevant intake24 instance has this option available, configured and that user is enrolled in Duo Security.</p><div class="tip custom-block"><p class="custom-block-title">To set up Duo Security as a multi-factor authentication provider:</p><ul><li><p>create Web SDK application in Duo Security admin panel</p></li><li><p>configure intake24 to use <a href="/config/api/security#duo-provider-settings">Duo Security as an authentication provider</a></p></li><li><p>user&#39;s <code>email</code> is passed to Duo Security as a primary identifier -&gt; Duo user accounts need to hold the email as primary identifier or as an additional alias</p></li></ul></div>',26)])])}const m=a(r,[["render",n]]);export{p as __pageData,m as default};
